import React, { useState } from 'react';
import { ADMIN_CREDENTIALS, PASSWORD_REQUIREMENTS } from '../constants';
import { db } from '../utils/storage';
import { User } from '../types';

interface LoginFormProps {
  onLoginSuccess: (user: User) => void;
}

const LoginForm: React.FC<LoginFormProps> = ({ onLoginSuccess }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const [isChangingPassword, setIsChangingPassword] = useState(false);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [pendingUser, setPendingUser] = useState<User | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    const input = username.trim().toLowerCase();

    // 1. Admin Master Hardcoded (Prioridade absoluta)
    if (input === ADMIN_CREDENTIALS.username && password === ADMIN_CREDENTIALS.password) {
      setTimeout(() => {
        onLoginSuccess({
          id: 'admin-master',
          username: 'operacional_ssz',
          displayName: 'Administrador Master',
          role: 'admin',
          lastLogin: new Date().toISOString(),
          position: 'Diretoria Operacional',
          isFirstLogin: false
        });
      }, 800);
      return;
    }

    try {
      const users = await db.getUsers();
      let foundUser = users.find(u => u.username.toLowerCase() === input);

      if (foundUser) {
        if (!foundUser.isFirstLogin && password === '12345678' && foundUser.password !== '12345678') {
          setError('A senha padrão não é mais válida. Utilize sua senha pessoal.');
          setIsLoading(false);
          return;
        }

        if (password === foundUser.password) {
          if (foundUser.isFirstLogin) {
            setPendingUser(foundUser);
            setIsChangingPassword(true);
            setIsLoading(false);
          } else {
            onLoginSuccess({ ...foundUser, lastLogin: new Date().toISOString() });
          }
        } else {
          setError('Credenciais incorretas. Verifique sua senha.');
        }
      } else {
        setError('Usuário não localizado no sistema.');
      }
    } catch (err) {
      setError('Falha de conexão com a base de dados.');
    } finally {
      setIsLoading(false);
    }
  };

  const handlePasswordUpdate = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (newPassword !== confirmPassword) {
      setError('As senhas digitadas não coincidem.');
      return;
    }

    if (newPassword.length < PASSWORD_REQUIREMENTS.minLength) { 
      setError(`A senha deve conter ao menos ${PASSWORD_REQUIREMENTS.minLength} caracteres.`); 
      return; 
    }

    if (newPassword === '12345678') {
      setError('Não utilize a senha padrão por questões de segurança.');
      return;
    }

    if (pendingUser) {
      setIsLoading(true);
      try {
        const updated: User = { 
          ...pendingUser, 
          password: newPassword,
          isFirstLogin: false,
          lastLogin: new Date().toISOString() 
        };

        await db.saveUser(updated);
        onLoginSuccess(updated);
      } catch (err) {
        setError('Erro ao processar a alteração no servidor.');
      } finally {
        setIsLoading(false);
      }
    }
  };

  return (
    <div className="flex items-center justify-center min-h-screen px-4 py-12">
      <div className="w-full max-w-md relative">
        {/* Decorative elements */}
        <div className="absolute -top-20 -left-20 w-40 h-40 bg-blue-600/20 rounded-full blur-3xl animate-pulse"></div>
        <div className="absolute -bottom-20 -right-20 w-40 h-40 bg-indigo-600/20 rounded-full blur-3xl animate-pulse delay-1000"></div>

        <div className="relative p-10 space-y-8 bg-white/95 backdrop-blur-xl rounded-[3.5rem] shadow-[0_32px_64px_-15px_rgba(0,0,0,0.5)] border border-white/50 animate-in fade-in zoom-in-95 duration-700">
          <div className="text-center">
            <div className="inline-flex items-center justify-center w-28 h-28 mb-8 rounded-[2rem] bg-slate-950 text-white shadow-2xl shadow-blue-500/10 ring-4 ring-slate-50">
              <span className="text-5xl font-black italic tracking-tighter">ALS</span>
            </div>
            <h2 className="text-3xl font-black text-slate-900 uppercase tracking-tighter leading-none">
               {isChangingPassword ? 'Nova Senha' : 'Acesso Restrito'}
            </h2>
            <p className="mt-3 text-[10px] text-slate-400 font-bold uppercase tracking-[0.4em] leading-relaxed">
               Logística & Transportes SSZ
            </p>
          </div>

          {isChangingPassword ? (
             <form className="mt-8 space-y-6" onSubmit={handlePasswordUpdate}>
                <div className="bg-blue-50/50 p-5 rounded-3xl border border-blue-100/50 mb-6">
                  <p className="text-[10px] text-blue-700 font-black uppercase text-center leading-tight">
                    Primeiro acesso detectado. Por segurança, altere sua senha para prosseguir ao portal.
                  </p>
                </div>
                <div className="space-y-4">
                   <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Nova Senha</label>
                      <input 
                          type="password" 
                          required 
                          autoFocus
                          className="w-full px-6 py-5 border border-slate-200 bg-slate-50/50 text-slate-900 font-bold rounded-2xl focus:border-blue-600 focus:bg-white outline-none transition-all shadow-inner" 
                          placeholder="••••••••" 
                          value={newPassword} 
                          onChange={e => setNewPassword(e.target.value)} 
                      />
                   </div>
                   <div className="space-y-1.5">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-3">Confirmar Senha</label>
                      <input 
                          type="password" 
                          required 
                          className="w-full px-6 py-5 border border-slate-200 bg-slate-50/50 text-slate-900 font-bold rounded-2xl focus:border-blue-600 focus:bg-white outline-none transition-all shadow-inner" 
                          placeholder="••••••••" 
                          value={confirmPassword} 
                          onChange={e => setConfirmPassword(e.target.value)} 
                      />
                   </div>
                </div>
                {error && <div className="p-4 text-[10px] font-black uppercase text-red-600 bg-red-50 rounded-2xl border border-red-100 animate-shake">{error}</div>}
                <button type="submit" disabled={isLoading} className="w-full py-6 bg-slate-950 text-white font-black uppercase text-xs tracking-[0.2em] rounded-[1.5rem] shadow-2xl hover:bg-blue-600 transition-all active:scale-95 disabled:opacity-50">
                  {isLoading ? 'PROCESSANDO...' : 'ATUALIZAR E ENTRAR'}
                </button>
             </form>
          ) : (
             <form className="mt-8 space-y-6" onSubmit={handleSubmit}>
                <div className="space-y-5">
                   <div className="space-y-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-3">Usuário Autorizado</label>
                      <input 
                        type="text" 
                        required 
                        autoFocus
                        autoComplete="username"
                        className="w-full px-6 py-5 border border-slate-100 bg-slate-50/50 text-slate-900 font-bold rounded-[1.5rem] focus:border-blue-500 focus:bg-white outline-none transition-all shadow-inner uppercase" 
                        placeholder="operacional_ssz"
                        value={username} 
                        onChange={(e) => setUsername(e.target.value)} 
                      />
                   </div>
                   <div className="space-y-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-3">Chave de Acesso</label>
                      <input 
                        type="password" 
                        required 
                        autoComplete="current-password"
                        className="w-full px-6 py-5 border border-slate-100 bg-slate-50/50 text-slate-900 font-bold rounded-[1.5rem] focus:border-blue-500 focus:bg-white outline-none transition-all shadow-inner" 
