                        value={password} 
                        onChange={(e) => setPassword(e.target.value)} 
                      />
                   </div>
                </div>
                {error && <div className="p-5 text-[10px] font-black uppercase text-red-600 bg-red-50/80 backdrop-blur rounded-[1.5rem] border border-red-100 animate-shake">{error}</div>}
                <button type="submit" disabled={isLoading} className="w-full py-6 bg-slate-950 text-white font-black uppercase text-xs tracking-[0.2em] rounded-[1.5rem] hover:bg-blue-600 shadow-[0_20px_40px_-10px_rgba(0,0,0,0.3)] transition-all active:scale-95 disabled:opacity-50 group">
                   <span className="flex items-center justify-center gap-2">
                      {isLoading ? 'AUTENTICANDO...' : 'INICIAR SESSÃO'}
                      {!isLoading && <svg className="w-4 h-4 transition-transform group-hover:translate-x-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7l5 5m0 0l-5 5m5-5H6" strokeWidth="3" strokeLinecap="round"/></svg>}
