                    <div className="grid grid-cols-2 gap-4">
                       <div className="space-y-1">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Privilégio</label>
                          <select disabled={!isAdmin} className={inputClasses} value={form.role} onChange={e => setForm({...form, role: e.target.value as any})}>
                             <option value="staff">Comum</option>
                             <option value="admin">Administrador</option>
                          </select>
                       </div>
                       <div className="space-y-1">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Status</label>
                          <select disabled={!isAdmin} className={inputClasses} value={form.status} onChange={e => setForm({...form, status: e.target.value as any})}>
                             <option value="Ativo">Ativo</option>
                             <option value="Inativo">Inativo</option>
                          </select>
                       </div>
                    </div>

                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-emerald-500 uppercase ml-1">Senha de Acesso</label>
                       <div className="flex gap-2">
                          <div className="relative flex-1">
                             <input 
                               type={showPass ? "text" : "password"}
                               required={!editingId || isEditingPassword}
                               disabled={editingId && !isEditingPassword}
                               className={`${inputClasses} pr-12`} 
                               placeholder={editingId && !isEditingPassword ? "••••••••" : "DIGITE A NOVA SENHA"}
                               value={isEditingPassword || !editingId ? form.password : ""}
                               onChange={e => setForm({...form, password: e.target.value})}
                             />
                             <button type="button" onClick={() => setShowPass(!showPass)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400">
                                {showPass ? (
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268-2.943-9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" strokeWidth="2.5"/></svg>
                                ) : (
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" strokeWidth="2.5"/><path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268-2.943-9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" strokeWidth="2.5"/></svg>
                                )}
                             </button>
                          </div>
                          {editingId && isAdmin && (
                            <button 
                              type="button" 
                              onClick={() => { 
                                setIsEditingPassword(!isEditingPassword); 
                                if (!isEditingPassword) setForm({...form, password: ''});
                              }} 
                              className={`px-4 rounded-2xl text-[9px] font-black uppercase transition-all ${isEditingPassword ? 'bg-red-100 text-red-600' : 'bg-blue-600 text-white shadow-lg'}`}
                            >
                              {isEditingPassword ? 'Cancelar' : 'Alterar'}
                            </button>
                          )}
                       </div>
                    </div>
                 </div>

                 <div className="pt-4">
                    <button type="submit" disabled={isProcessing} className="w-full py-5 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-blue-600 transition-all flex items-center justify-center gap-3">
                      {isProcessing ? 'Gravando...' : editingId ? 'Salvar Alterações' : 'Criar Colaborador'}
                    </button>
                 </div>
              </form>
           </div>
        </div>
      )}
    </div>
  );
});

export default StaffTab;

import React, { useState, useEffect, useRef } from 'react';
import { User, Driver, DashboardTab, Port, PreStacking, Customer, OperationDefinition, Staff } from '../types';
import OverviewTab from './dashboard/OverviewTab';
import DriversTab from './dashboard/DriversTab';
import FormsTab from './dashboard/FormsTab';
import CustomersTab from './dashboard/CustomersTab';
import PortsTab from './dashboard/PortsTab';
import PreStackingTab from './dashboard/PreStackingTab';
import OperationsTab from './dashboard/OperationsTab';
import StaffTab from './dashboard/StaffTab';
import SystemTab from './dashboard/SystemTab';
import WeatherWidget from './dashboard/WeatherWidget';
import OnlineStatus from './dashboard/OnlineStatus';
import { DEFAULT_OPERATIONS } from '../constants/operations';
import { db } from '../utils/storage';
import { sessionManager } from '../utils/session';

interface DashboardProps {
  user: User;
  onLogout: () => void;
}

const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState<DashboardTab>(DashboardTab.INICIO);
  const [expandedMenus, setExpandedMenus] = useState<Record<string, boolean>>({});
  const [sessionDuration, setSessionDuration] = useState('00:00:00');
  const [isProfileMenuOpen, setIsProfileMenuOpen] = useState(false);
  const [sidebarState, setSidebarState] = useState<'open' | 'collapsed' | 'hidden'>('open');
  const [forceProfileModal, setForceProfileModal] = useState<string | null>(null);
  const [selectedFormId, setSelectedFormId] = useState<string | null>(null);

  const profileMenuRef = useRef<HTMLDivElement>(null);
  const [drivers, setDrivers] = useState<Driver[]>([]);
  const [customers, setCustomers] = useState<Customer[]>([]);
  const [ports, setPorts] = useState<Port[]>([]);
  const [preStacking, setPreStacking] = useState<PreStacking[]>([]);
  const [staffList, setStaffList] = useState<Staff[]>([]);
  const [availableOps, setAvailableOps] = useState<OperationDefinition[]>(DEFAULT_OPERATIONS);

  const [opsView, setOpsView] = useState<{ type: 'list' | 'category' | 'client', id?: string, categoryName?: string, clientName?: string }>({ 
    type: 'list'
  });

  const loadAllData = async () => {
    try {
      const [d, c, p, ps, s] = await Promise.all([
        db.getDrivers(), 
        db.getCustomers(), 
        db.getPorts(), 
        db.getPreStacking(), 
        db.getStaff()
      ]);
      setDrivers(d || []); 
      setCustomers(c || []); 
      setPorts(p || []); 
      setPreStacking(ps || []); 
      setStaffList(s || []);
    } catch (e) { 
      console.error("Erro ao carregar dados:", e); 
    }
  };

  useEffect(() => {
    loadAllData();

    const subscriptions = [
      db.subscribe('staff', loadAllData),
      db.subscribe('users', async (payload) => {
        await loadAllData();
        const isValid = await sessionManager.validateIntegrity(user);
        if (!isValid) {
          alert("Sua sessão expirou devido a uma alteração cadastral ou de segurança.");
          onLogout();
        }
      }),
      db.subscribe('drivers', loadAllData),
      db.subscribe('customers', loadAllData),
      db.subscribe('ports', loadAllData),
      db.subscribe('pre_stacking', loadAllData)
    ];

    const timer = setInterval(() => {
      const now = new Date();
      const loginTime = new Date(user.lastLogin).getTime();
      const diff = now.getTime() - loginTime;

      if (diff > 0) {
        const hours = Math.floor(diff / 3600000).toString().padStart(2, '0');
        const minutes = Math.floor((diff % 3600000) / 60000).toString().padStart(2, '0');
        const seconds = Math.floor((diff % 60000) / 1000).toString().padStart(2, '0');
        setSessionDuration(`${hours}:${minutes}:${seconds}`);
      }

      // Heartbeat para monitoramento Ativo/Ausente
      if (now.getSeconds() % 15 === 0) {
        db.updateHeartbeat(user.id);
      }
    }, 1000);

    const handleVisibilityChange = () => {
      db.updateHeartbeat(user.id);
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);

    const handleClickOutside = (event: MouseEvent) => {
      if (profileMenuRef.current && !profileMenuRef.current.contains(event.target as Node)) {
        setIsProfileMenuOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);

    return () => {
      clearInterval(timer);
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('visibilitychange', handleVisibilityChange);
      subscriptions.forEach(sub => sub?.unsubscribe());
    };
  }, [user, onLogout]);

  const toggleMenuExpansion = (key: string) => {
    setExpandedMenus(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const handleFormClick = (formId: string) => {
    setSelectedFormId(null);
    setTimeout(() => {
      setActiveTab(DashboardTab.FORMULARIOS);
      setSelectedFormId(formId);
    }, 10);
  };

  const MenuItem = ({ 
    tab, 
    label, 
    icon, 
    adminOnly, 
    children,
    forceActive = false
  }: { 
    tab?: DashboardTab, 
    label: string, 
    icon?: React.ReactNode, 
    adminOnly?: boolean,
    children?: React.ReactNode,
    forceActive?: boolean
  }) => {
    if (adminOnly && user.role !== 'admin') return null;
    const isActive = forceActive || (tab ? activeTab === tab : false);
    const isExpanded = expandedMenus[label];

    return (
      <div className="w-full">
        <div className="flex items-center group">
          <button 
            onClick={() => {
              if (tab) {
                setActiveTab(tab);
                if (tab === DashboardTab.OPERACOES) setOpsView({ type: 'list' });
                if (tab !== DashboardTab.FORMULARIOS) setSelectedFormId(null);
              } else if (children) {
                toggleMenuExpansion(label);
              }
            }}
            className={`flex-1 flex items-center gap-3 px-5 py-3 rounded-xl transition-all font-bold text-[10px] uppercase tracking-widest ${isActive ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-800/60 text-slate-400'}`}
          >
            {icon || <div className="w-4 h-4 rounded bg-white/10 flex-shrink-0" />}
            {sidebarState === 'open' && <span className="truncate">{label}</span>}
          </button>

          {children && sidebarState === 'open' && (
            <button 
              onClick={(e) => { e.stopPropagation(); toggleMenuExpansion(label); }}
              className={`p-3 text-slate-500 hover:text-white transition-all ${isExpanded ? 'rotate-180' : ''}`}
            >
              <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 9l-7 7-7-7" strokeWidth="3"/></svg>
            </button>
          )}
        </div>

        {children && isExpanded && sidebarState === 'open' && (
          <div className="ml-8 mt-1 space-y-1 border-l border-slate-800/50 pl-4 animate-in slide-in-from-top-2 duration-200">
            {children}
          </div>
        )}
      </div>
    );
  };

  const handleEditProfile = () => {
    setIsProfileMenuOpen(false);
    if (user.staffId) {
       setActiveTab(DashboardTab.COLABORADORES);
       setForceProfileModal(user.staffId);
    }
  };

  const cycleSidebar = () => {
    if (sidebarState === 'open') setSidebarState('collapsed');
    else if (sidebarState === 'collapsed') setSidebarState('hidden');
    else setSidebarState('open');
  };

  const myStaffData = staffList.find(s => s.id === user.staffId);
  const displayEmail = user.emailCorp || myStaffData?.emailCorp || 'financeiro@als.com.br';
  const displayPhone = user.phoneCorp || myStaffData?.phoneCorp || '(13) 99762-0041';

  return (
    <div className="flex h-screen bg-[#f8fafc] overflow-hidden font-sans text-slate-900">
      <aside className={`
        ${sidebarState === 'open' ? 'w-80' : sidebarState === 'collapsed' ? 'w-20' : 'w-0'} 
        bg-[#0f172a] text-slate-400 flex flex-col shadow-2xl z-50 transition-all duration-300 relative overflow-hidden
      `}>
        <div className="p-5 border-b border-slate-800/50 space-y-4">
          <div className="flex items-center gap-3 mb-2 overflow-hidden">
            <div className="bg-blue-600 w-9 h-9 min-w-[36px] rounded-xl flex items-center justify-center text-white font-black italic">ALS</div>
            {sidebarState === 'open' && <span className="block font-black text-slate-100 tracking-wider text-xs uppercase whitespace-nowrap">ALS TRANSPORTES</span>}
          </div>
          {sidebarState === 'open' && <WeatherWidget />}
        </div>

        <nav className="flex-1 p-3 space-y-1 overflow-y-auto custom-scrollbar">
          <MenuItem tab={DashboardTab.INICIO} label="Início" />
          <MenuItem tab={DashboardTab.OPERACOES} label="Operações" forceActive={activeTab === DashboardTab.OPERACOES}>
            {availableOps.map(op => (
              <div key={op.id} className="group/cat">
                <div className="flex items-center justify-between py-1.5 px-2 hover:bg-slate-800/40 rounded-lg group">
                  <button onClick={() => { setActiveTab(DashboardTab.OPERACOES); setOpsView({ type: 'category', id: op.id, categoryName: op.category }); }} className="text-[9px] font-bold uppercase text-slate-500 hover:text-white transition-colors flex-1 text-left">• {op.category}</button>
                  {op.clients.length > 0 && (
                    <button onClick={() => toggleMenuExpansion(`op-${op.id}`)} className="p-1 text-slate-600 hover:text-blue-400">
                      <svg className={`w-2.5 h-2.5 transition-transform ${expandedMenus[`op-${op.id}`] ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 9l-7 7-7-7" strokeWidth="3"/></svg>
                    </button>
                  )}
                </div>
                {expandedMenus[`op-${op.id}`] && (
                  <div className="ml-4 space-y-1 mb-2 animate-in slide-in-from-left-1">
                    {op.clients.map((client, idx) => (
                      <button key={idx} onClick={() => { if (client.hasDedicatedPage) { setActiveTab(DashboardTab.OPERACOES); setOpsView({ type: 'client', id: op.id, categoryName: op.category, clientName: client.name }); } }} className={`w-full text-left py-1 text-[8px] font-black uppercase transition-colors px-2 rounded hover:bg-slate-800/30 ${client.hasDedicatedPage ? 'text-blue-500 hover:text-blue-300' : 'text-slate-600 opacity-60 cursor-default'}`}>└ {client.name}</button>
                    ))}
                  </div>
                )}
              </div>
            ))}
          </MenuItem>
          <MenuItem tab={DashboardTab.MOTORISTAS} label="Motoristas" />
          <MenuItem tab={DashboardTab.FORMULARIOS} label="Formulários" forceActive={activeTab === DashboardTab.FORMULARIOS}>
            <button onClick={() => handleFormClick('ORDEM_COLETA')} className="w-full text-left px-2 py-2 text-[9px] font-black uppercase text-slate-500 hover:text-white hover:bg-slate-800/30 rounded">• Ordem de Coleta</button>
            <button onClick={() => handleFormClick('PRE_STACKING')} className="w-full text-left px-2 py-2 text-[9px] font-black uppercase text-slate-500 hover:text-white hover:bg-slate-800/30 rounded">• Pré-Stacking</button>
            <button onClick={() => handleFormClick('LIBERACAO_VAZIO')} className="w-full text-left px-2 py-2 text-[9px] font-black uppercase text-slate-500 hover:text-white hover:bg-slate-800/30 rounded">• Liberação Vazio</button>
            <button onClick={() => handleFormClick('RETIRADA_CHEIO')} className="w-full text-left px-2 py-2 text-[9px] font-black uppercase text-slate-500 hover:text-white hover:bg-slate-800/30 rounded">• Retirada Cheio</button>
          </MenuItem>
          <MenuItem tab={DashboardTab.CLIENTES} label="Clientes" />
          <MenuItem tab={DashboardTab.PORTOS} label="Portos" />
          <MenuItem tab={DashboardTab.PRE_STACKING} label="Pré-Stacking" />
          <div className="pt-4 pb-2">
             {sidebarState === 'open' && <p className="px-4 text-[7px] font-black text-slate-600 uppercase mb-2 tracking-[0.2em]">Administração</p>}
             <MenuItem tab={DashboardTab.COLABORADORES} label="Equipe ALS" />
             <MenuItem tab={DashboardTab.SISTEMA} label="Configurações" adminOnly />
          </div>
        </nav>

        <div className="p-4 border-t border-slate-800/50 bg-[#0f172a] space-y-3">
           {sidebarState === 'open' && <OnlineStatus staffList={staffList} />}
           <button onClick={onLogout} className="w-full text-[8px] text-red-500 font-black uppercase hover:bg-red-500/10 py-3 rounded-xl flex items-center justify-center gap-2 border border-red-900/20 active:scale-95 transition-all">
             <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M17 16l4-4m0 0l-4-4m4 4H7" strokeWidth="3"/></svg>
             {sidebarState === 'open' && <span>Encerrar Sessão</span>}
           </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 shadow-sm z-40">
           <div className="flex items-center gap-4">
              <button onClick={cycleSidebar} className="p-2 hover:bg-slate-100 rounded-xl text-slate-400 transition-all active:scale-90"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 6h16M4 12h16m-7 6h7" strokeWidth="2.5" strokeLinecap="round"/></svg></button>
              <div className="h-6 w-[1px] bg-slate-200 hidden sm:block"></div>
              <h2 className="text-[10px] font-black text-slate-800 uppercase tracking-[0.2em]">{activeTab}</h2>
           </div>

           <div className="flex items-center gap-4 relative" ref={profileMenuRef}>
              <button onClick={() => setIsProfileMenuOpen(!isProfileMenuOpen)} className="flex items-center gap-2.5 p-1.5 hover:bg-slate-50 rounded-xl transition-all border border-transparent hover:border-slate-100 group">
                 <div className="text-right hidden sm:block">
                    <p className="text-[9px] font-black text-slate-800 uppercase group-hover:text-blue-600 transition-colors leading-none">{user.displayName || 'Usuário'}</p>
                    <p className="text-[7px] font-bold text-slate-400 uppercase tracking-widest mt-1 leading-none">{user.position || 'Operacional'}</p>
                 </div>
                 <div className="w-9 h-9 rounded-xl bg-slate-900 flex items-center justify-center font-black text-blue-400 text-xs overflow-hidden shadow-md group-hover:scale-105 transition-all">
                    {user.photo ? <img src={user.photo} className="w-full h-full object-cover" /> : (user.displayName || 'A').substring(0,1).toUpperCase()}
                 </div>
              </button>

              {isProfileMenuOpen && (
                <div className="absolute top-full right-0 mt-2 w-80 bg-white rounded-3xl shadow-2xl border border-slate-100 p-6 z-[100] animate-in slide-in-from-top-4 backdrop-blur-xl bg-white/95">
                  <div className="text-center mb-5 pb-5 border-b border-slate-50">
                    <div className="w-16 h-16 rounded-2xl bg-blue-600 text-white flex items-center justify-center text-2xl font-black mx-auto mb-3 overflow-hidden shadow-lg border-4 border-white">
                      {user.photo ? <img src={user.photo} className="w-full h-full object-cover" /> : (user.displayName || 'A').substring(0,1).toUpperCase()}
                    </div>
                    <h4 className="font-black text-slate-800 uppercase text-xs">{user.displayName}</h4>
                    <p className="text-[8px] text-blue-500 font-bold uppercase tracking-widest mt-1">{user.position || 'OPERACIONAL'}</p>
                    <div className="mt-4 bg-slate-900 text-white p-3 rounded-2xl shadow-inner border border-white/5 overflow-hidden text-center flex flex-col items-center">
                       <p className="text-[7px] font-black text-blue-400 uppercase tracking-[0.2em] mb-1">Tempo de Sessão</p>
                       <div className="text-lg font-black font-mono tracking-tighter">{sessionDuration}</div>
                    </div>
                  </div>
                  <div className="space-y-2 mb-5">
                    <div className="flex flex-col gap-0.5 px-3 py-2 bg-slate-50 rounded-xl border border-slate-100 text-center"><span className="text-[7px] font-black text-slate-400 uppercase">E-mail Corporativo</span><span className="text-[9px] font-bold text-slate-800 lowercase break-all">{displayEmail}</span></div>
                    <div className="flex flex-col gap-0.5 px-3 py-2 bg-slate-50 rounded-xl border border-slate-100 text-center"><span className="text-[7px] font-black text-slate-400 uppercase">Telefone Corp.</span><span className="text-[9px] font-bold text-slate-800">{displayPhone}</span></div>
                  </div>
                  <div className="space-y-1.5">
                    <button onClick={handleEditProfile} className="w-full py-3 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-blue-600 transition-all shadow-md active:scale-95">Editar Perfil</button>
                    <button onClick={onLogout} className="w-full py-3 bg-red-50 text-red-500 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-red-500 hover:text-white transition-all active:scale-95">Sair do Sistema</button>
                  </div>
                </div>
              )}
           </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 bg-[#f8fafc] custom-scrollbar">
           {activeTab === DashboardTab.INICIO && <OverviewTab trips={[]} />}
           {activeTab === DashboardTab.MOTORISTAS && <DriversTab drivers={drivers} onSaveDriver={async (d, id) => { await db.saveDriver({...d, id: id || `drv-${Date.now()}`} as Driver); loadAllData(); }} onDeleteDriver={async id => { if(confirm("Apagar?")) { await db.deleteDriver(id); loadAllData(); } }} availableOps={availableOps} />}
           {activeTab === DashboardTab.COLABORADORES && <StaffTab staffList={staffList} currentUser={user} forceEditStaffId={forceProfileModal} onCloseForceEdit={() => setForceProfileModal(null)} onSaveStaff={async (s, p) => { await db.saveStaff(s, p); await loadAllData(); }} onDeleteStaff={async id => { if(confirm("Apagar?")) { await db.deleteStaff(id); loadAllData(); } }} />}
           {activeTab === DashboardTab.OPERACOES && <OperationsTab availableOps={availableOps} setAvailableOps={setAvailableOps} drivers={drivers} activeView={opsView} setActiveView={setOpsView} vwSchedules={[]} onSaveVWSchedule={()=>{}} onUpdateVWStatus={()=>{}} />}
           {activeTab === DashboardTab.CLIENTES && <CustomersTab customers={customers} onSaveCustomer={async (c, id) => { await db.saveCustomer({...c, id: id || `cust-${Date.now()}`} as Customer); loadAllData(); }} />}
           {activeTab === DashboardTab.PORTOS && <PortsTab ports={ports} onSavePort={async (p, id) => { await db.savePort({...p, id: id || `port-${Date.now()}`} as Port); loadAllData(); }} />}
           {activeTab === DashboardTab.PRE_STACKING && <PreStackingTab preStacking={preStacking} onSavePreStacking={async (ps, id) => { await db.savePreStacking({...ps, id: id || `ps-${Date.now()}`} as PreStacking); loadAllData(); }} />}
           {activeTab === DashboardTab.FORMULARIOS && <FormsTab drivers={drivers} customers={customers} ports={ports} initialFormId={selectedFormId} />}
           {user.role === 'admin' && activeTab === DashboardTab.SISTEMA && <SystemTab onRefresh={loadAllData} driversCount={drivers.length} customersCount={customers.length} portsCount={ports.length} />}
        </div>
      </main>
    </div>
  );
};

export default Dashboard;

import React, { useState, useRef, useEffect, forwardRef } from 'react';
import { Staff, User } from '../../types';
import { db } from '../../utils/storage';
import { maskPhone } from '../../utils/masks';

interface StaffTabProps {
  staffList: Staff[];
  currentUser: User;
  onSaveStaff: (staff: Staff, password?: string) => Promise<void>;
  onDeleteStaff: (id: string) => Promise<void>;
  forceEditStaffId?: string | null;
  onCloseForceEdit?: () => void;
}

const StaffTab = forwardRef<HTMLDivElement, StaffTabProps>(({ 
  staffList, 
  currentUser, 
  onSaveStaff, 
  onDeleteStaff, 
  forceEditStaffId, 
  onCloseForceEdit 
}, ref) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | undefined>(undefined);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const [isEditingPassword, setIsEditingPassword] = useState(false);

  const [form, setForm] = useState<Partial<Staff & { password?: string }>>({ 
    name: '', position: '', username: '', role: 'staff', password: '', emailCorp: '', phoneCorp: '', status: 'Ativo' 
  });

  const [users, setUsers] = useState<User[]>([]);
  const [showPasswordsList, setShowPasswordsList] = useState<Record<string, boolean>>({});
  const [usernameOptions, setUsernameOptions] = useState<string[]>([]);
  const photoRef = useRef<HTMLInputElement>(null);

  // Extrair todos os cargos únicos existentes na equipe para o datalist
  const existingPositions = Array.from(new Set(staffList.map(s => s.position).filter(Boolean))).sort();

  const loadUsers = async () => {
    const u = await db.getUsers();
    setUsers(u);
  };

  useEffect(() => {
    loadUsers();
  }, [staffList, isModalOpen]);

  useEffect(() => {
    if (forceEditStaffId) {
      const staff = staffList.find(s => s.id === forceEditStaffId);
      if (staff) {
        handleEdit(staff);
        if (onCloseForceEdit) onCloseForceEdit();
      }
    }
  }, [forceEditStaffId, staffList]);

  const isAdmin = currentUser.role === 'admin';
  const canEdit = (staffId: string) => isAdmin || currentUser.staffId === staffId;

  // Gerador automático de sugestões de usuário baseado no nome
  useEffect(() => {
    if (form.name && !editingId) {
      const cleanName = form.name.trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
      const parts = cleanName.split(/\s+/);

      if (parts.length > 1) {
        const first = parts[0];
        const options = parts.slice(1).map(surname => `${first}.${surname}`);
        const uniqueOptions = options.filter(opt => !users.some(u => u.username === opt));
        setUsernameOptions(uniqueOptions);
        if (!uniqueOptions.includes(form.username || '')) {
           setForm(prev => ({ ...prev, username: uniqueOptions[0] || '' }));
        }
      } else {
        setUsernameOptions([]);
        const basicUser = parts[0] || '';
        if (!users.some(u => u.username === basicUser)) {
           setForm(prev => ({ ...prev, username: basicUser }));
        }
      }
    }
  }, [form.name, editingId, users]);

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isProcessing) return;

    setIsProcessing(true);
    try {
      const staffId = editingId || `stf-${Date.now()}`;
      const existing = staffList.find(s => s.id === staffId);

      const staffData: Staff = { 
        id: staffId,
        name: (form.name || '').toUpperCase(),
        position: (form.position || '').toUpperCase(),
        username: (form.username || '').toLowerCase(),
        role: (form.role as 'admin' | 'staff') || 'staff',
        photo: form.photo,
        registrationDate: existing?.registrationDate || new Date().toISOString(),
        emailCorp: (form.emailCorp || '').toLowerCase(),
        phoneCorp: form.phoneCorp || '',
        // Removido do formulário: Status é sempre Ativo no cadastro inicial 
        // ou mantém o atual se estiver editando
        status: existing?.status || 'Ativo',
        statusSince: existing?.statusSince || new Date().toISOString()
      };

      const passwordToSave = (!editingId || isEditingPassword) ? form.password : undefined;

      await onSaveStaff(staffData, passwordToSave);
      setIsModalOpen(false);
      setIsEditingPassword(false);
      setShowPass(false);
      loadUsers();
    } catch (err: any) {
      alert(`FALHA: ${err.message || 'Erro ao salvar.'}`);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleEdit = (s: Staff) => {
    const linkedUser = users.find(u => u.staffId === s.id);
    setForm({ ...s, password: linkedUser?.password || '' });
    setEditingId(s.id);
    setShowPass(false);
    setIsEditingPassword(false);
    setIsModalOpen(true);
  };

  const inputClasses = "w-full px-5 py-3.5 rounded-2xl border border-slate-200 bg-white font-bold outline-none focus:border-blue-500 text-slate-900 shadow-sm transition-all placeholder:text-slate-300 disabled:bg-slate-50 disabled:text-slate-400";

  return (
    <div className="space-y-6" ref={ref}>
      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm flex items-center justify-between">
        <div>
          <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight">Equipe ALS</h2>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Gestão de Contatos e Acessos</p>
        </div>
        {isAdmin && (
          <button 
            onClick={() => { 
              setForm({ role: 'staff', name: '', position: '', username: '', password: '12345678', emailCorp: '', phoneCorp: '', status: 'Ativo' }); 
              setEditingId(undefined); 
              setIsEditingPassword(true);
              setIsModalOpen(true); 
            }} 
            className="px-6 py-4 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-emerald-600 transition-all active:scale-95"
          >
            Novo Colaborador
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {staffList.map(s => {
          const linkedUser = users.find(u => u.staffId === s.id);
          const isPassVisible = showPasswordsList[s.id];
          const hasEditRights = canEdit(s.id);

          return (
            <div key={s.id} className={`bg-white rounded-[2.5rem] p-8 border ${s.status === 'Inativo' ? 'border-red-100' : 'border-slate-200'} shadow-sm hover:shadow-xl transition-all flex flex-col`}>
              <div className="flex items-center gap-6">
                 <div className="relative">
                    <div className="w-16 h-16 rounded-2xl bg-slate-100 border border-slate-200 overflow-hidden flex items-center justify-center">
                        {s.photo ? <img src={s.photo} className="w-full h-full object-cover" /> : <span className="font-black text-slate-300 italic text-[10px]">ALS</span>}
                    </div>
                    <div className={`absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-white ${s.status === 'Ativo' ? 'bg-emerald-500' : 'bg-red-500'}`}></div>
                 </div>
                 <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                       <h4 className="font-black text-slate-800 uppercase text-sm leading-tight truncate">{s.name}</h4>
                       {s.role === 'admin' && <span className="px-1.5 py-0.5 bg-blue-100 text-blue-600 rounded text-[6px] font-black uppercase">Admin</span>}
                    </div>
                    <p className="text-[10px] text-blue-500 font-bold uppercase mt-1">{s.position}</p>
                 </div>
              </div>

              <div className="mt-6 space-y-3 pt-6 border-t border-slate-50 flex-1">
                 <div className="flex justify-between items-center text-[9px] font-black uppercase tracking-widest">
                    <span className="text-slate-400">Usuário</span>
                    <span className="text-blue-600 bg-blue-50 px-2 py-1 rounded-lg lowercase font-bold">{s.username}</span>
                 </div>

                 <div className="flex justify-between items-center text-[9px] font-black uppercase tracking-widest">
                    <span className="text-slate-400">Contatos</span>
                    <div className="text-right">
                       <p className="text-[9px] font-bold text-slate-700">{s.phoneCorp || '(13) ---- ----'}</p>
                       <p className="text-[8px] font-bold text-blue-500 lowercase">{s.emailCorp || 'sem e-mail corp.'}</p>
                    </div>
                 </div>

                 {isAdmin && (
                   <div className="flex justify-between items-center text-[9px] font-black uppercase tracking-widest">
                      <span className="text-slate-400">Senha Operacional</span>
                      <div className="flex items-center gap-2">
                        <span className="text-emerald-600 font-mono text-[10px] font-black">
                          {isPassVisible ? (linkedUser?.password || '---') : '••••••••'}
                        </span>
                        <button onClick={() => setShowPasswordsList(prev => ({ ...prev, [s.id]: !prev[s.id] }))} className="p-1 text-slate-300 hover:text-blue-500 transition-colors">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            {isPassVisible ? (
                               <path d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268-2.943-9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" strokeWidth="2.5"/>
                            ) : (
                               <path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" strokeWidth="2.5"/><path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268-2.943-9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" strokeWidth="2.5"/>
                            )}
                          </svg>
                        </button>
                      </div>
                   </div>
                 )}
              </div>

              {hasEditRights && (
                <div className="mt-6 flex gap-2">
                   <button onClick={() => handleEdit(s)} className="flex-1 py-3 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase hover:bg-blue-600 transition-all shadow-md">Editar Cadastro</button>
                   {isAdmin && (
                     <button onClick={() => onDeleteStaff(s.id)} className="px-4 py-3 bg-red-50 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all">
                       <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" strokeWidth="2.5"/></svg>
                     </button>
                   )}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md">
           <div className="bg-white w-full max-w-xl rounded-[3rem] shadow-2xl border border-slate-200 overflow-hidden animate-in zoom-in-95">
              <div className="p-8 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                 <h3 className="font-black text-slate-800 text-sm uppercase tracking-widest">{editingId ? 'Perfil Colaborador' : 'Novo Colaborador'}</h3>
                 <button onClick={() => setIsModalOpen(false)} className="text-slate-300 hover:text-red-400 transition-all"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="2.5"/></svg></button>
              </div>
              <form onSubmit={handleSave} className="p-10 space-y-4 max-h-[85vh] overflow-y-auto custom-scrollbar">
                 <div className="flex justify-center mb-4">
                    <div onClick={() => photoRef.current?.click()} className="w-20 h-20 rounded-3xl bg-slate-100 border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer hover:border-blue-500 transition-all">
                       {form.photo ? <img src={form.photo} className="w-full h-full object-cover rounded-3xl" /> : <span className="text-[9px] font-black text-slate-400 uppercase text-center">FOTO</span>}
                    </div>
                    <input type="file" ref={photoRef} className="hidden" accept="image/*" onChange={e => {
                       const f = e.target.files?.[0];
                       if (f) {
                          const reader = new FileReader();
                          reader.onload = () => setForm({...form, photo: reader.result as string});
                          reader.readAsDataURL(f);
                       }
                    }} />
                 </div>

                 <div className="space-y-4">
                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Nome Completo</label>
                       <input required className={`${inputClasses} uppercase`} value={form.name} onChange={e => setForm({...form, name: e.target.value.toUpperCase()})} />
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                       <div className="space-y-1">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Telefone Corp. (Opcional)</label>
                          <input className={inputClasses} value={form.phoneCorp} onChange={e => setForm({...form, phoneCorp: maskPhone(e.target.value)})} placeholder="(13) 99999-9999" />
                       </div>
                       <div className="space-y-1">
                          <label className="text-[9px] font-black text-slate-400 uppercase ml-1">E-mail Corp. (Opcional)</label>
                          <input className={`${inputClasses} lowercase`} value={form.emailCorp} onChange={e => setForm({...form, emailCorp: e.target.value})} placeholder="nome@als.com.br" />
                       </div>
                    </div>

                    <div className="bg-blue-50 p-6 rounded-2xl border border-blue-100 space-y-3">
                       <label className="text-[9px] font-black text-blue-600 uppercase ml-1">Usuário de Acesso</label>
                       {!editingId ? (
                         <div className="flex flex-wrap gap-2">
                           {usernameOptions.map(opt => (
                             <button key={opt} type="button" onClick={() => setForm(prev => ({ ...prev, username: opt }))} className={`px-3 py-2 rounded-xl text-[9px] font-black uppercase transition-all border ${form.username === opt ? 'bg-blue-600 text-white border-blue-600 shadow-md' : 'bg-white text-blue-400 border-blue-200'}`}>
                               {opt}
                             </button>
                           ))}
                         </div>
                       ) : (
                         <div className="px-4 py-3 bg-slate-100 border border-slate-200 rounded-xl text-xs font-black text-slate-400 lowercase">{form.username}</div>
                       )}
                    </div>

                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Cargo</label>
                       <input 
                         required 
                         list="positions-list" 
                         className={`${inputClasses} uppercase`} 
                         value={form.position} 
                         onChange={e => setForm({...form, position: e.target.value.toUpperCase()})} 
                         placeholder="DIGITE OU SELECIONE UM CARGO"
                       />
                       <datalist id="positions-list">
                         {existingPositions.map(pos => (
                           <option key={pos} value={pos} />
                         ))}
                       </datalist>
                       <p className="text-[7px] text-slate-400 font-bold uppercase italic mt-1 ml-1">* Você pode criar um novo cargo simplesmente digitando-o.</p>
                    </div>

                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-slate-400 uppercase ml-1">Privilégio de Sistema</label>
                       <select disabled={!isAdmin} className={inputClasses} value={form.role} onChange={e => setForm({...form, role: e.target.value as any})}>
                          <option value="staff">OPERACIONAL COMUM</option>
                          <option value="admin">ADMINISTRADOR MASTER</option>
                       </select>
                    </div>

                    <div className="space-y-1">
                       <label className="text-[9px] font-black text-emerald-500 uppercase ml-1">Senha de Acesso</label>
                       <div className="flex gap-2">
                          <div className="relative flex-1">
                             <input 
                               type={showPass ? "text" : "password"}
                               required={!editingId || isEditingPassword}
                               disabled={editingId && !isEditingPassword}
                               className={`${inputClasses} pr-12`} 
                               placeholder={editingId && !isEditingPassword ? "••••••••" : "DEFINIR NOVA SENHA"}
                               value={isEditingPassword || !editingId ? form.password : ""}
                               onChange={e => setForm({...form, password: e.target.value})}
                             />
                             <button type="button" onClick={() => setShowPass(!showPass)} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400">
                                {showPass ? (
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268-2.943-9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" strokeWidth="2.5"/></svg>
                                ) : (
                                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" strokeWidth="2.5"/><path d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268-2.943-9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" strokeWidth="2.5"/></svg>
                                )}
                             </button>
                          </div>
                          {editingId && isAdmin && (
                            <button 
                              type="button" 
                              onClick={() => { 
                                setIsEditingPassword(!isEditingPassword); 
                                if (!isEditingPassword) setForm({...form, password: ''});
                              }} 
                              className={`px-4 rounded-2xl text-[9px] font-black uppercase transition-all ${isEditingPassword ? 'bg-red-100 text-red-600' : 'bg-blue-600 text-white shadow-lg'}`}
                            >
                              {isEditingPassword ? 'Cancelar' : 'Alterar'}
                            </button>
                          )}
                       </div>
                    </div>
                 </div>

                 <div className="pt-4">
                    <button type="submit" disabled={isProcessing} className="w-full py-5 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-blue-600 transition-all flex items-center justify-center gap-3">
                      {isProcessing ? 'Gravando...' : editingId ? 'Salvar Alterações' : 'Criar Colaborador'}
                    </button>
                 </div>
              </form>
           </div>
        </div>
      )}
    </div>
