        </div>
        {isAdmin && (
          <button 
            onClick={() => { 
              setForm({ role: 'staff', name: '', position: '', username: '', password: '12345678', emailCorp: '', phoneCorp: '', status: 'Ativo' }); 
              setEditingId(undefined); 
