  RETIRADA_CHEIO: { title: 'Retirada de Cheio', color: 'bg-indigo-600', description: 'Ordem para movimentação de container importado' },
};

const FormsTab: React.FC<FormsTabProps> = ({ drivers, customers, ports, initialFormId }) => {
  const [selectedFormType, setSelectedFormType] = useState<FormType | null>(null);
  const [isFormModalOpen, setIsFormModalOpen] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  const [driverSearch, setDriverSearch] = useState('');
  const [showDriverResults, setShowDriverResults] = useState(false);
  const [remetenteSearch, setRemetenteSearch] = useState('');
  const [showRemetenteResults, setShowRemetenteResults] = useState(false);
  const [destinatarioSearch, setDestinatarioSearch] = useState('');
  const [showDestinatarioResults, setShowDestinatarioResults] = useState(false);

  const captureRef = useRef<HTMLDivElement>(null);

  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    driverId: '',
    remetenteId: '',
    destinatarioId: '',
    os: '',
    container: '',
    tara: '',
    seal: '',
    booking: '',
    ship: '',
    expedidor: '',
    agencia: 'ALIANÇA',
    tipo: '40HC',
    padrao: 'EXPORTAÇÃO',
    tipoOperacao: 'EXPORTAÇÃO',
    autColeta: '',
    embarcador: '',
    genset: '',
    nf: '',
    horarioAgendado: '',
    obs: ''
  });

  useEffect(() => {
    if (initialFormId && formConfigs[initialFormId as FormType]) {
      setSelectedFormType(initialFormId as FormType);
      setIsFormModalOpen(true);
    }
  }, [initialFormId]);

  const generateBarcodes = (container: string, tara: string, seal: string) => {
    if (selectedFormType !== 'ORDEM_COLETA') return;
    const generate = (id: string, value: string) => {
      const el = document.getElementById(id);
      if (el && value) {
        try {
          JsBarcode(`#${id}`, value, { format: "CODE128", width: 2, height: 25, displayValue: false, margin: 0, background: "transparent" });
        } catch (e) { }
      }
    };
    generate('barcode-container', container);
    generate('barcode-tara', tara);
    generate('barcode-lacre', seal);
  };

  useEffect(() => {
    if (isFormModalOpen && selectedFormType === 'ORDEM_COLETA') {
      setTimeout(() => generateBarcodes(formData.container, formData.tara, formData.seal), 500);
    }
  }, [formData, isFormModalOpen, selectedFormType]);

  const handleInputChange = (field: string, value: string) => {
    const upValue = value.toUpperCase();
    if (field === 'container') {
      const carrier = findCarrierByPrefix(upValue);
      setFormData(prev => ({ ...prev, container: upValue, agencia: carrier ? carrier.name : prev.agencia }));
    } else if (field === 'seal') {
      setFormData(prev => ({ ...prev, seal: maskSeal(upValue, formData.agencia) }));
    } else {
      setFormData(prev => ({ ...prev, [field]: upValue }));
    }
  };

  const selectedDriver = drivers.find(d => d.id === formData.driverId);
  const selectedRemetente = customers.find(c => c.id === formData.remetenteId);
  const selectedDestinatario = ports.find(p => p.id === formData.destinatarioId);

  const downloadPDF = async () => {
    setIsExporting(true);
    try {
      if (selectedFormType === 'ORDEM_COLETA') generateBarcodes(formData.container, formData.tara, formData.seal);
      await new Promise(r => setTimeout(r, 800));
      const element = captureRef.current;
      if (!element) return;
      const canvas = await html2canvas(element, { scale: 2.5, useCORS: true, backgroundColor: "#ffffff" });
      const imgData = canvas.toDataURL('image/jpeg', 0.98);
      const pdf = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });
      pdf.addImage(imgData, 'JPEG', 0, 0, 210, 297);
      pdf.save(`${selectedFormType === 'ORDEM_COLETA' ? 'OC' : 'MINUTA'}-${formData.os}.pdf`);
    } catch (e) { console.error(e); } finally { setIsExporting(false); }
  };

  const inputClasses = "w-full px-4 py-3 rounded-xl border border-slate-200 bg-white text-slate-700 font-bold uppercase focus:border-blue-500 outline-none transition-all";

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      <div style={{ position: 'absolute', left: '-9999px', top: '-9999px' }}>
        <div ref={captureRef}>
          {selectedFormType === 'ORDEM_COLETA' && <OrdemColetaTemplate formData={formData} selectedDriver={selectedDriver} selectedRemetente={selectedRemetente} selectedDestinatario={selectedDestinatario} />}
          {selectedFormType === 'PRE_STACKING' && <PreStackingTemplate formData={formData} selectedDriver={selectedDriver} selectedRemetente={selectedRemetente} selectedDestinatario={selectedDestinatario} />}
        </div>
      </div>

      <div className="bg-white p-10 rounded-[2.5rem] border border-slate-200 shadow-sm">
        <h2 className="text-xl font-black text-slate-800 uppercase tracking-tight mb-8 text-center">Central de Emissões</h2>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {(Object.keys(formConfigs) as FormType[]).map(type => (
            <button key={type} onClick={() => { setSelectedFormType(type); setIsFormModalOpen(true); }} className="flex items-center gap-6 p-6 bg-slate-50 border border-slate-100 rounded-[2rem] hover:bg-white hover:border-blue-500 hover:shadow-xl transition-all group text-left">
              <div className={`w-14 h-14 ${formConfigs[type].color} rounded-2xl flex items-center justify-center text-white font-black italic shadow-lg`}>ALS</div>
              <div className="flex-1">
                <h3 className="font-black text-slate-700 uppercase text-xs">{formConfigs[type].title}</h3>
                <p className="text-[9px] text-slate-400 font-bold uppercase mt-1 leading-tight">{formConfigs[type].description}</p>
              </div>
            </button>
          ))}
        </div>
      </div>

      {isFormModalOpen && selectedFormType && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md">
          <div className="bg-white w-full max-w-[1700px] rounded-[3rem] shadow-2xl border border-slate-200 overflow-hidden flex flex-col h-[95vh]">
            <div className={`p-6 ${formConfigs[selectedFormType].color} text-white flex justify-between items-center`}>
              <h3 className="font-black text-sm uppercase tracking-widest">{formConfigs[selectedFormType].title}</h3>
              <button onClick={() => setIsFormModalOpen(false)} className="w-10 h-10 flex items-center justify-center bg-white/20 rounded-full hover:bg-white/40"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="3"/></svg></button>
            </div>

            <div className="flex-1 flex flex-col lg:flex-row overflow-hidden">
              <div className="w-full lg:w-[480px] p-8 overflow-y-auto space-y-5 bg-slate-50/50 border-r border-slate-100 custom-scrollbar">
                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Emissão (Auto)</label><div className="px-4 py-3 bg-slate-200 rounded-xl text-slate-500 font-black text-xs">{new Date().toLocaleDateString('pt-BR')}</div></div>
                  <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Nº OS</label><input type="text" className={inputClasses} value={formData.os} onChange={e => handleInputChange('os', e.target.value)} /></div>
                </div>

                <div className="space-y-1 relative">
                  <label className="text-[9px] font-black text-blue-600 uppercase tracking-widest ml-1">Remetente</label>
                  <input type="text" placeholder="BUSCAR CLIENTE..." className={inputClasses} value={remetenteSearch} onFocus={() => setShowRemetenteResults(true)} onChange={e => { setRemetenteSearch(e.target.value.toUpperCase()); setShowRemetenteResults(true); }} />
                  {showRemetenteResults && (
                    <div className="absolute z-50 w-full mt-1 bg-white border border-slate-200 rounded-xl shadow-2xl max-h-48 overflow-y-auto">
                      {customers.filter(c => c.name.toUpperCase().includes(remetenteSearch)).map(c => <button key={c.id} className="w-full text-left px-4 py-3 hover:bg-blue-50 text-[10px] font-bold uppercase" onClick={() => { setFormData({...formData, remetenteId: c.id}); setRemetenteSearch(c.name); setShowRemetenteResults(false); }}>{c.name}</button>)}
                    </div>
                  )}
                </div>

                <div className="space-y-1 relative">
                  <label className="text-[9px] font-black text-blue-600 uppercase tracking-widest ml-1">Destinatário</label>
                  <input type="text" placeholder="BUSCAR PORTO..." className={inputClasses} value={destinatarioSearch} onFocus={() => setShowDestinatarioResults(true)} onChange={e => { setDestinatarioSearch(e.target.value.toUpperCase()); setShowDestinatarioResults(true); }} />
                  {showDestinatarioResults && (
                    <div className="absolute z-50 w-full mt-1 bg-white border border-slate-200 rounded-xl shadow-2xl max-h-48 overflow-y-auto">
                      {ports.filter(p => p.name.toUpperCase().includes(destinatarioSearch)).map(p => <button key={p.id} className="w-full text-left px-4 py-3 hover:bg-blue-50 text-[10px] font-bold uppercase" onClick={() => { setFormData({...formData, destinatarioId: p.id}); setDestinatarioSearch(p.name); setShowDestinatarioResults(false); }}>{p.name}</button>)}
                    </div>
                  )}
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Armador</label><input type="text" className={inputClasses} value={formData.agencia} onChange={e => handleInputChange('agencia', e.target.value)} /></div>
                  <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo Equip.</label><input type="text" className={inputClasses} value={formData.tipo} onChange={e => handleInputChange('tipo', e.target.value)} /></div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Padrão</label><input type="text" className={inputClasses} value={formData.padrao} onChange={e => handleInputChange('padrao', e.target.value)} /></div>
                  <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Operação</label><input type="text" className={inputClasses} value={formData.tipoOperacao} onChange={e => handleInputChange('tipoOperacao', e.target.value)} /></div>
                </div>

                <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Aut. Coleta / CVA</label><input type="text" className={inputClasses} value={formData.autColeta} onChange={e => handleInputChange('autColeta', e.target.value)} /></div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Container</label><input type="text" className={inputClasses} value={formData.container} onChange={e => handleInputChange('container', e.target.value)} /></div>
                  <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Tara</label><input type="text" className={inputClasses} value={formData.tara} onChange={e => handleInputChange('tara', e.target.value)} /></div>
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Lacre</label><input type="text" className={inputClasses} value={formData.seal} onChange={e => handleInputChange('seal', e.target.value)} /></div>
                  <div className="space-y-1"><label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Genset</label><input type="text" className={inputClasses} value={formData.genset} onChange={e => handleInputChange('genset', e.target.value)} /></div>
                </div>

                <div className="space-y-1 relative">
                  <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Motorista</label>
                  <input type="text" placeholder="BUSCAR MOTORISTA..." className={inputClasses} value={driverSearch} onFocus={() => setShowDriverResults(true)} onChange={e => { setDriverSearch(e.target.value.toUpperCase()); setShowDriverResults(true); }} />
                  {showDriverResults && (
                    <div className="absolute z-10 w-full mt-1 bg-white border border-slate-200 rounded-xl shadow-2xl max-h-48 overflow-y-auto">
                      {drivers.filter(d => d.name.toUpperCase().includes(driverSearch)).map(d => <button key={d.id} className="w-full text-left px-4 py-3 hover:bg-blue-50 text-[10px] font-bold uppercase" onClick={() => { setFormData({...formData, driverId: d.id}); setDriverSearch(d.name); setShowDriverResults(false); }}>{d.name}</button>)}
                    </div>
                  )}
                </div>

                <div className="bg-blue-50/50 p-6 rounded-3xl border border-blue-100 space-y-2">
                  <label className="text-[9px] font-black text-blue-600 uppercase tracking-widest ml-1">Agendamento de Coleta</label>
                  <input type="datetime-local" className={inputClasses} value={formData.horarioAgendado} onChange={e => setFormData({...formData, horarioAgendado: e.target.value})} />
                </div>

                <button disabled={isExporting} onClick={downloadPDF} className="w-full py-5 bg-slate-900 text-white rounded-[2rem] text-xs font-black uppercase tracking-widest hover:bg-blue-600 shadow-xl transition-all">
                  {isExporting ? 'GERANDO PDF...' : 'BAIXAR DOCUMENTO'}
                </button>
              </div>

              <div className="flex-1 bg-slate-200 flex justify-center overflow-auto p-10">
                <div className="origin-top transform scale-75 xl:scale-90 shadow-2xl">
                  {selectedFormType === 'ORDEM_COLETA' && <OrdemColetaTemplate formData={formData} selectedDriver={selectedDriver} selectedRemetente={selectedRemetente} selectedDestinatario={selectedDestinatario} />}
                  {selectedFormType === 'PRE_STACKING' && <PreStackingTemplate formData={formData} selectedDriver={selectedDriver} selectedRemetente={selectedRemetente} selectedDestinatario={selectedDestinatario} />}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default FormsTab;

import { createClient } from '@supabase/supabase-js';
import { Driver, Customer, Port, PreStacking, Staff, User } from '../types';

// Obtain environment variables for Supabase configuration
const SUPABASE_URL = (import.meta as any).env?.VITE_SUPABASE_URL || '';
const SUPABASE_KEY = (import.meta as any).env?.VITE_SUPABASE_ANON_KEY || '';

// Initialize Supabase client if credentials are provided
export const supabase = (SUPABASE_URL && SUPABASE_KEY) ? createClient(SUPABASE_URL, SUPABASE_KEY) : null;

// Storage keys for local persistence
export const KEYS = {
  DRIVERS: 'als_drivers',
  CUSTOMERS: 'als_customers',
  PORTS: 'als_ports',
  PRE_STACKING: 'als_pre_stacking',
  STAFF: 'als_staff',
  USERS: 'als_users'
};

/**
 * db object provides an abstraction layer for data management, 
 * handling both local storage for offline use and Supabase for cloud sync.
 */
export const db = {
  // Helper to persist data to localStorage
  _saveLocal: (key: string, data: any) => {
    localStorage.setItem(key, JSON.stringify(data));
  },

  // Checks if the cloud connection is active
  isCloudActive: () => !!supabase,

  // --- User Management ---
  getUsers: async (): Promise<User[]> => {
    const localData = JSON.parse(localStorage.getItem(KEYS.USERS) || '[]');
    if (supabase) {
      try {
        const { data } = await supabase.from('users').select('*');
        if (data) { db._saveLocal(KEYS.USERS, data); return data; }
      } catch (e) { console.warn("Supabase getUsers offline."); }
    }
    return localData;
  },

  saveUser: async (user: User) => {
    const current = JSON.parse(localStorage.getItem(KEYS.USERS) || '[]');
    const idx = current.findIndex((u: any) => u.id === user.id);
    let updated;
    if (idx >= 0) { updated = [...current]; updated[idx] = user; } else { updated = [...current, user]; }
    db._saveLocal(KEYS.USERS, updated);
    if (supabase) await supabase.from('users').upsert(user);
  },

  // --- Driver Management ---
  getDrivers: async (): Promise<Driver[]> => {
    const localData = JSON.parse(localStorage.getItem(KEYS.DRIVERS) || '[]');
    if (supabase) {
      try {
        const { data } = await supabase.from('drivers').select('*');
        if (data) { db._saveLocal(KEYS.DRIVERS, data); return data; }
      } catch (e) { console.warn("Supabase getDrivers offline."); }
    }
    return localData;
  },

  saveDriver: async (driver: Driver) => {
    const current = JSON.parse(localStorage.getItem(KEYS.DRIVERS) || '[]');
    const idx = current.findIndex((d: any) => d.id === driver.id);
    let updated;
    if (idx >= 0) { updated = [...current]; updated[idx] = driver; } else { updated = [...current, driver]; }
    db._saveLocal(KEYS.DRIVERS, updated);
    if (supabase) await supabase.from('drivers').upsert(driver);
  },

  deleteDriver: async (id: string) => {
    const current = JSON.parse(localStorage.getItem(KEYS.DRIVERS) || '[]');
    db._saveLocal(KEYS.DRIVERS, current.filter((d: any) => d.id !== id));
    if (supabase) await supabase.from('drivers').delete().eq('id', id);
    return true;
  },

  // --- Customer Management ---
  getCustomers: async (): Promise<Customer[]> => {
    const localData = JSON.parse(localStorage.getItem(KEYS.CUSTOMERS) || '[]');
    if (supabase) {
      try {
        const { data } = await supabase.from('customers').select('*');
        if (data) { db._saveLocal(KEYS.CUSTOMERS, data); return data; }
      } catch (e) { console.warn("Supabase getCustomers offline."); }
    }
    return localData;
  },

  saveCustomer: async (customer: Customer) => {
    const current = JSON.parse(localStorage.getItem(KEYS.CUSTOMERS) || '[]');
    const idx = current.findIndex((c: any) => c.id === customer.id);
    let updated;
    if (idx >= 0) { updated = [...current]; updated[idx] = customer; } else { updated = [...current, customer]; }
    db._saveLocal(KEYS.CUSTOMERS, updated);
    if (supabase) await supabase.from('customers').upsert(customer);
  },

  deleteCustomer: async (id: string) => {
    const current = JSON.parse(localStorage.getItem(KEYS.CUSTOMERS) || '[]');
    db._saveLocal(KEYS.CUSTOMERS, current.filter((c: any) => c.id !== id));
    if (supabase) await supabase.from('customers').delete().eq('id', id);
    return true;
  },

  // --- Port Management ---
  getPorts: async (): Promise<Port[]> => {
    const localData = JSON.parse(localStorage.getItem(KEYS.PORTS) || '[]');
    if (supabase) {
      try {
        const { data } = await supabase.from('ports').select('*');
        if (data) { db._saveLocal(KEYS.PORTS, data); return data; }
      } catch (e) { console.warn("Supabase getPorts offline."); }
    }
    return localData;
  },

  savePort: async (port: Port) => {
    const current = JSON.parse(localStorage.getItem(KEYS.PORTS) || '[]');
    const idx = current.findIndex((p: any) => p.id === port.id);
    let updated;
    if (idx >= 0) { updated = [...current]; updated[idx] = port; } else { updated = [...current, port]; }
    db._saveLocal(KEYS.PORTS, updated);
    if (supabase) await supabase.from('ports').upsert(port);
  },

  deletePort: async (id: string) => {
    const current = JSON.parse(localStorage.getItem(KEYS.PORTS) || '[]');
    db._saveLocal(KEYS.PORTS, current.filter((p: any) => p.id !== id));
    if (supabase) await supabase.from('ports').delete().eq('id', id);
    return true;
  },

  // --- PreStacking Management ---
  getPreStacking: async (): Promise<PreStacking[]> => {
    const localData = JSON.parse(localStorage.getItem(KEYS.PRE_STACKING) || '[]');
    if (supabase) {
      try {
        const { data } = await supabase.from('pre_stacking').select('*');
        if (data) { db._saveLocal(KEYS.PRE_STACKING, data); return data; }
      } catch (e) { console.warn("Supabase getPreStacking offline."); }
    }
    return localData;
  },

  savePreStacking: async (ps: PreStacking) => {
    const current = JSON.parse(localStorage.getItem(KEYS.PRE_STACKING) || '[]');
    const idx = current.findIndex((p: any) => p.id === ps.id);
    let updated;
    if (idx >= 0) { updated = [...current]; updated[idx] = ps; } else { updated = [...current, ps]; }
    db._saveLocal(KEYS.PRE_STACKING, updated);
    if (supabase) await supabase.from('pre_stacking').upsert(ps);
  },

  deletePreStacking: async (id: string) => {
    const current = JSON.parse(localStorage.getItem(KEYS.PRE_STACKING) || '[]');
    db._saveLocal(KEYS.PRE_STACKING, current.filter((p: any) => p.id !== id));
    if (supabase) await supabase.from('pre_stacking').delete().eq('id', id);
    return true;
  },

  // --- Staff Management ---
  getStaff: async (): Promise<Staff[]> => {
    const localData = JSON.parse(localStorage.getItem(KEYS.STAFF) || '[]');
    if (supabase) {
      try {
        const { data } = await supabase.from('staff').select('*');
        if (data) { db._saveLocal(KEYS.STAFF, data); return data; }
      } catch (e) { console.warn("Supabase getStaff offline."); }
    }
    return localData;
  },

  saveStaff: async (staff: Staff, password?: string) => {
    const current = JSON.parse(localStorage.getItem(KEYS.STAFF) || '[]');
    const idx = current.findIndex((s: any) => s.id === staff.id);
    let updated;
    if (idx >= 0) { updated = [...current]; updated[idx] = staff; } else { updated = [...current, staff]; }
    db._saveLocal(KEYS.STAFF, updated);
    if (supabase) await supabase.from('staff').upsert(staff);

    // Sync with User table for authentication
    const users = await db.getUsers();
    const existingUser = users.find(u => u.staffId === staff.id);

    const userData: User = {
      id: existingUser?.id || `u-${staff.id}`,
      username: staff.username,
      displayName: staff.name,
      role: staff.role,
      staffId: staff.id,
      lastLogin: existingUser?.lastLogin || new Date().toISOString(),
      position: staff.position,
      photo: staff.photo,
      status: staff.status,
      password: password || existingUser?.password
    };

    await db.saveUser(userData);
  },

  deleteStaff: async (id: string) => {
    const current = JSON.parse(localStorage.getItem(KEYS.STAFF) || '[]');
    db._saveLocal(KEYS.STAFF, current.filter((s: any) => s.id !== id));
    if (supabase) await supabase.from('staff').delete().eq('id', id);

    // Also delete associated user record
    const users = await db.getUsers();
    const user = users.find(u => u.staffId === id);
    if (user) {
      const remainingUsers = users.filter(u => u.id !== user.id);
      db._saveLocal(KEYS.USERS, remainingUsers);
      if (supabase) await supabase.from('users').delete().eq('id', user.id);
    }
    return true;
  },

  // --- Backup & Restore ---
  exportBackup: async () => {
    const backup = {
      drivers: await db.getDrivers(),
      customers: await db.getCustomers(),
      ports: await db.getPorts(),
      preStacking: await db.getPreStacking(),
      staff: await db.getStaff(),
      users: await db.getUsers()
    };
    const blob = new Blob([JSON.stringify(backup, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `als_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  },

  importBackup: async (file: File): Promise<boolean> => {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onload = async (e) => {
        try {
          const content = JSON.parse(e.target?.result as string);
          if (content.drivers) {
            db._saveLocal(KEYS.DRIVERS, content.drivers);
            if (supabase) await supabase.from('drivers').upsert(content.drivers);
          }
          if (content.customers) {
            db._saveLocal(KEYS.CUSTOMERS, content.customers);
            if (supabase) await supabase.from('customers').upsert(content.customers);
          }
          if (content.ports) {
            db._saveLocal(KEYS.PORTS, content.ports);
            if (supabase) await supabase.from('ports').upsert(content.ports);
          }
          if (content.preStacking) {
            db._saveLocal(KEYS.PRE_STACKING, content.preStacking);
            if (supabase) await supabase.from('pre_stacking').upsert(content.pre_stacking);
          }
          if (content.staff) {
            db._saveLocal(KEYS.STAFF, content.staff);
            if (supabase) await supabase.from('staff').upsert(content.staff);
          }
          if (content.users) {
            db._saveLocal(KEYS.USERS, content.users);
            if (supabase) await supabase.from('users').upsert(content.users);
          }
          resolve(true);
        } catch (err) {
          console.error("Import failed:", err);
          resolve(false);
        }
      };
      reader.readAsText(file);
    });
  }
};

