                      <option value="IMPORTAÇÃO">IMPORTAÇÃO</option>
                    </select>
                  </div>

                  <div className="space-y-1">
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Navio / Viagem</label>
                    <input type="text" placeholder="NOME DO NAVIO..." className={inputClasses} value={formData.ship} onChange={e => handleInputChange('ship', e.target.value)} />
