                  <div 
                    className="bg-gradient-to-br from-blue-50 to-indigo-50 p-6 rounded-3xl border border-blue-200 space-y-2 shadow-inner group cursor-pointer active:scale-[0.98] transition-all relative overflow-hidden" 
                    onClick={handleAgendamentoClick}
                  >
                    <div className="flex justify-between items-center relative z-10">
                      <label className="text-[9px] font-black text-blue-600 uppercase tracking-widest ml-1 pointer-events-none">Agendamento de Coleta (Data/Hora)</label>
