                    </div>
                    <input 
                      type="datetime-local" 
                      ref={dateTimeInputRef}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-20"
                      value={formData.horarioAgendado} 
                      onChange={e => setFormData({...formData, horarioAgendado: e.target.value})} 
                      onClick={(e) => e.stopPropagation()}
                    />
                    <div className="text-slate-800 font-black uppercase text-base min-h-[1.5rem] relative z-10 pointer-events-none">
                      {formData.horarioAgendado ? new Date(formData.horarioAgendado).toLocaleString('pt-BR') : 'SELECIONAR DATA/HORA'}
