            <OrdemColetaTemplate 
              formData={{...formData, displayDate: emissionDate}} 
              selectedDriver={selectedDriver} 
              selectedRemetente={selectedRemetente} 
              selectedDestinatario={selectedDestinatario} 
            />
          )}
